module.render:
const esc = (s) => String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
const body = sections[0] ? sections[0].trim() : '';
const fs = { small: '0.75em', medium: '0.85em', large: '1em' }[String(args.size || 'medium').toLowerCase()] || '0.85em';
const variant = String(args.variant || 'default').toLowerCase();
const pressed = String(args.pressed) === 'true';
const cls = 'mdp-mod-kbd' + (variant === 'dark' ? ' mdp-kbd-dark' : '') + (pressed ? ' mdp-kbd-pressed' : '');
return '<kbd class="' + cls + '" style="font-size:' + fs + ';">' + esc(body) + '</kbd>';
